    public Map save(HashMap config) throws AppException, ParseException {
        String guid = (String) config.get("mainguid");
        String backcontent = (String) config.get("backcontent");
        Map<String,Object> backMap = new HashMap<String, Object>();
        //当前登录用户
        UserDTO user = SecureUtil.getCurrentUser();
        if(null != guid && !"".equals(guid)){
            Map map = null;
            List<Map> datas = getDataByGuid(guid);
            if (datas != null && datas.size() > 0) {//修改
                map = datas.get(0);
                map.put("feedbackcontent", backcontent);
                map.put("updateuid", user.getGuid());
                map.put("updateuname", user.getName());
                map.put("updatetime", StringUtil.getSysDBDate());
                feedbackInfoDAO.update(map, RectificationAddProjDAO.PERF_T_RECTIFY);
            }
            backMap.put("success", true);
        }
        return backMap;
    }
    /**
     *  查询反馈信息
     * @param guid
     * @return
     */
    private List getDataByGuid(String guid) {
        return feedbackInfoDAO.getByGuid(RectificationAddProjDAO.PERF_T_RECTIFY, guid);
    }

